data: {"created":"2026-03-11T17:00:05.129049261Z","hasMore":true,"id":"msg_01CvvoRogV8vh6A5Qj9gPQRF","items":[{"arguments":"{\"command\": \"cd /home/nanobot/sessions/2120ea74-b7f3-4eb4-abfe-145b7ad213d5 \u0026\u0026 MCP_CONFIG_PATH=.nanobot/mcp_servers.json mcp-cli info duckduckgo search\"}","callID":"toolu_012CUPQiGr9Mw8jQFiWd3SSy","id":"msg_01CvvoRogV8vh6A5Qj9gPQRF-0","name":"bash","output":{"content":[{"text":"Tool: search\nServer: duckduckgo\n\nDescription:\n  \nSearch DuckDuckGo and return formatted results.\n\nArgs:\n    query: The search query string\n    max_results: Maximum number of results to return (default: 10)\n    ctx: MCP context for logging\n\n\nInput Schema:\n{\n  \"type\": \"object\",\n  \"properties\": {\n    \"max_results\": {\n      \"default\": 10,\n      \"title\": \"Max Results\",\n      \"type\": \"integer\"\n    },\n    \"query\": {\n      \"title\": \"Query\",\n      \"type\": \"string\"\n    }\n  },\n  \"required\": [\n    \"query\"\n  ],\n  \"title\": \"searchArguments\"\n}\n","type":"text"}]},"partial":true,"type":"tool"},{"arguments":"{\"command\": \"cd /home/nanobot/sessions/2120ea74-b7f3-4eb4-abfe-145b7ad213d5 \u0026\u0026 MCP_CONFIG_PATH=.nanobot/mcp_servers.json mcp-cli info duckduckgo fetch_content\"}","callID":"toolu_01526cqk3YkQwZFMdE3Zdm9A","id":"msg_01CvvoRogV8vh6A5Qj9gPQRF-1","name":"bash","output":{"content":[{"text":"Tool: fetch_content\nServer: duckduckgo\n\nDescription:\n  \nFetch and parse content from a webpage URL.\n\nArgs:\n    url: The webpage URL to fetch content from\n    ctx: MCP context for logging\n\n\nInput Schema:\n{\n  \"type\": \"object\",\n  \"properties\": {\n    \"url\": {\n      \"title\": \"Url\",\n      \"type\": \"string\"\n    }\n  },\n  \"required\": [\n    \"url\"\n  ],\n  \"title\": \"fetch_contentArguments\"\n}\n","type":"text"}]},"partial":true,"type":"tool"}],"role":"assistant"}

