data: {"created":"2026-03-11T18:10:08.534406965Z","hasMore":true,"id":"msg_016kv5cAub9kSyyRo6DJiRHA","items":[{"arguments":"{\"command\": \"cd /home/nanobot/sessions/65b2a187-f291-4135-bbd0-e55583084d49 \u0026\u0026 MCP_CONFIG_PATH=.nanobot/mcp_servers.json mcp-cli info duckduckgo search\", \"description\": \"Get search tool schema\"}","callID":"toolu_018AVXg6qR1FroNyRR3o1KoR","id":"msg_016kv5cAub9kSyyRo6DJiRHA-0","name":"bash","output":{"content":[{"text":"Tool: search\nServer: duckduckgo\n\nDescription:\n  \nSearch DuckDuckGo and return formatted results.\n\nArgs:\n    query: The search query string\n    max_results: Maximum number of results to return (default: 10)\n    ctx: MCP context for logging\n\n\nInput Schema:\n{\n  \"type\": \"object\",\n  \"properties\": {\n    \"max_results\": {\n      \"default\": 10,\n      \"title\": \"Max Results\",\n      \"type\": \"integer\"\n    },\n    \"query\": {\n      \"title\": \"Query\",\n      \"type\": \"string\"\n    }\n  },\n  \"required\": [\n    \"query\"\n  ],\n  \"title\": \"searchArguments\"\n}\n","type":"text"}]},"partial":true,"type":"tool"},{"arguments":"{\"command\": \"cd /home/nanobot/sessions/65b2a187-f291-4135-bbd0-e55583084d49 \u0026\u0026 MCP_CONFIG_PATH=.nanobot/mcp_servers.json mcp-cli info duckduckgo fetch_content\", \"description\": \"Get fetch_content tool schema\"}","callID":"toolu_019beTKZMNGArhXpYcureN3Q","id":"msg_016kv5cAub9kSyyRo6DJiRHA-1","name":"bash","output":{"content":[{"text":"Tool: fetch_content\nServer: duckduckgo\n\nDescription:\n  \nFetch and parse content from a webpage URL.\n\nArgs:\n    url: The webpage URL to fetch content from\n    ctx: MCP context for logging\n\n\nInput Schema:\n{\n  \"type\": \"object\",\n  \"properties\": {\n    \"url\": {\n      \"title\": \"Url\",\n      \"type\": \"string\"\n    }\n  },\n  \"required\": [\n    \"url\"\n  ],\n  \"title\": \"fetch_contentArguments\"\n}\n","type":"text"}]},"partial":true,"type":"tool"}],"role":"assistant"}

